CREATE TYPE "Role" AS ENUM ('INTERNAL','ADMIN');
CREATE TYPE "StatusPoin" AS ENUM ('SUDAH_DILAKSANAKAN','DALAM_PROSES','BELUM_DILAKSANAKAN');
CREATE TYPE "PenanggungJawab" AS ENUM ('KEUANGAN_UMUM_LOGISTIK','TEKNIS_PEMILU_HUKUM','PERENCANAAN_DATA_INFORMASI','PARTISIPASI_MASYARAKAT_SDM');
CREATE TABLE "users" ("id" TEXT NOT NULL,"name" TEXT NOT NULL,"email" TEXT NOT NULL,"password_hash" TEXT NOT NULL,"role" "Role" NOT NULL,"created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updated_at" TIMESTAMP(3) NOT NULL,CONSTRAINT "users_pkey" PRIMARY KEY ("id"));
CREATE TABLE "berita_acara" ("id" TEXT NOT NULL,"nomor" TEXT NOT NULL,"nama" TEXT NOT NULL,"tanggal" DATE NOT NULL,"bulan" INTEGER NOT NULL,"tahun" INTEGER NOT NULL,"dokumen_url" TEXT NOT NULL,"deskripsi" TEXT,"created_by" TEXT NOT NULL,"created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updated_at" TIMESTAMP(3) NOT NULL,CONSTRAINT "berita_acara_pkey" PRIMARY KEY ("id"));
CREATE TABLE "poin_rencana" ("id" TEXT NOT NULL,"berita_acara_id" TEXT NOT NULL,"detail_poin" TEXT NOT NULL,"target_pelaksanaan" DATE NOT NULL,"status" "StatusPoin" NOT NULL DEFAULT 'BELUM_DILAKSANAKAN',"penanggung_jawab" "PenanggungJawab" NOT NULL,"indikator_output" TEXT NOT NULL,"catatan" TEXT,"created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updated_at" TIMESTAMP(3) NOT NULL,CONSTRAINT "poin_rencana_pkey" PRIMARY KEY ("id"));
CREATE TABLE "evidence" ("id" TEXT NOT NULL,"poin_rencana_id" TEXT NOT NULL,"judul" TEXT NOT NULL,"evidence_url" TEXT NOT NULL,"keterangan" TEXT,"created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updated_at" TIMESTAMP(3) NOT NULL,CONSTRAINT "evidence_pkey" PRIMARY KEY ("id"));
CREATE TABLE "riwayat_update" ("id" TEXT NOT NULL,"poin_rencana_id" TEXT NOT NULL,"field" TEXT NOT NULL,"nilai_lama" TEXT,"nilai_baru" TEXT,"diubah_oleh" TEXT NOT NULL,"created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "riwayat_update_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "users_email_key" ON "users"("email"); CREATE UNIQUE INDEX "berita_acara_nomor_key" ON "berita_acara"("nomor");
CREATE INDEX "berita_acara_tahun_bulan_idx" ON "berita_acara"("tahun","bulan"); CREATE INDEX "berita_acara_tanggal_idx" ON "berita_acara"("tanggal");
CREATE INDEX "poin_rencana_berita_acara_id_idx" ON "poin_rencana"("berita_acara_id"); CREATE INDEX "poin_rencana_status_idx" ON "poin_rencana"("status"); CREATE INDEX "poin_rencana_penanggung_jawab_idx" ON "poin_rencana"("penanggung_jawab"); CREATE INDEX "poin_rencana_target_pelaksanaan_idx" ON "poin_rencana"("target_pelaksanaan");
CREATE INDEX "evidence_poin_rencana_id_idx" ON "evidence"("poin_rencana_id"); CREATE INDEX "riwayat_update_poin_rencana_id_created_at_idx" ON "riwayat_update"("poin_rencana_id","created_at");
ALTER TABLE "berita_acara" ADD CONSTRAINT "berita_acara_created_by_fkey" FOREIGN KEY ("created_by") REFERENCES "users"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "poin_rencana" ADD CONSTRAINT "poin_rencana_berita_acara_id_fkey" FOREIGN KEY ("berita_acara_id") REFERENCES "berita_acara"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "evidence" ADD CONSTRAINT "evidence_poin_rencana_id_fkey" FOREIGN KEY ("poin_rencana_id") REFERENCES "poin_rencana"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "riwayat_update" ADD CONSTRAINT "riwayat_update_poin_rencana_id_fkey" FOREIGN KEY ("poin_rencana_id") REFERENCES "poin_rencana"("id") ON DELETE CASCADE ON UPDATE CASCADE;
